
public class 정적메모리 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		// 프로그램이 실행되기(run)전에 메모리의 크기가 정해지는 것을 말함
		
		// int: 4바이트, double: 8바이트, char: 2바이트, boolean: 1바이트
		int a=10;
		int c=20;
		System.out.println(a);
		System.out.println(c);
		
		// 지역변수: 함수안에서 만들어지는 벼수, 함수가 끝나면 사라짐(메모리해제, 반납)
	}

}
